// js/questions-y10.js — Year 10 NSW Science question bank (syllabus-aligned, regenerated)
window.QUESTION_BANK = window.QUESTION_BANK || {};
window.QUESTION_BANK[10] = {
  "genetics": [
    { q: "What molecule carries the genetic code in most living organisms?", o: ["Ribonucleic acid (RNA)", "Deoxyribonucleic acid (DNA)", "Adenosine triphosphate (ATP)", "Protein"], a: 1, exp: "DNA (deoxyribonucleic acid) is the molecule that stores the genetic instructions in most organisms." },
    { q: "How many different nucleotide bases are found in a DNA molecule?", o: ["2", "3", "4", "6"], a: 2, exp: "DNA uses four bases: adenine (A), thymine (T), cytosine (C), and guanine (G)." },
    { q: "What is the correct complementary base pairing rule for DNA?", o: ["A pairs with C, and T pairs with G", "A pairs with G, and T pairs with C", "A pairs with T, and C pairs with G", "A pairs with U, and C pairs with G"], a: 2, exp: "In DNA, adenine always pairs with thymine (A-T) and cytosine always pairs with guanine (C-G)." },
    { q: "Which term describes the complete set of genetic information in an organism?", o: ["Gene", "Chromosome", "Genome", "Allele"], a: 2, exp: "The genome is the complete set of genetic information, including all chromosomes, in an organism." },
    { q: "A typical human body cell contains how many chromosomes?", o: ["23", "46", "44", "48"], a: 1, exp: "Human body (somatic) cells contain 46 chromosomes arranged as 23 homologous pairs." },
    { q: "How many chromosomes does a human egg or sperm cell contain?", o: ["46", "48", "23", "22"], a: 2, exp: "Gametes (sex cells) contain 23 chromosomes — half the normal number — produced by meiosis." },
    { q: "What is the role of histones in relation to DNA?", o: ["They replicate DNA", "They are proteins around which DNA is coiled to form chromosomes", "They are the bases that pair together", "They carry genetic information between cells"], a: 1, exp: "Histone proteins act as spools around which DNA winds tightly, allowing it to be packaged into chromosomes." },
    { q: "What is a gene?", o: ["The entire DNA molecule in a cell", "A specific segment of DNA that encodes one protein or functional RNA", "Any section of a chromosome", "A pair of chromosomes"], a: 1, exp: "A gene is a specific sequence of DNA bases that carries the instructions for making a particular protein or functional RNA." },
    { q: "The two 'sides' of the DNA double helix are made of:", o: ["Alternating bases and proteins", "Alternating sugar and phosphate groups", "Pairs of nitrogenous bases", "Ribose and phosphate groups"], a: 1, exp: "The sugar-phosphate backbone (deoxyribose alternating with phosphate groups) forms the two sides of the DNA ladder." },
    { q: "Why is complementary base pairing important for DNA replication?", o: ["It allows genes to be expressed as proteins", "It enables each strand to act as a template for building a new complementary strand", "It determines the structure of histones", "It allows mutations to occur"], a: 1, exp: "Because each base pairs specifically with its partner, each separated strand can template the rebuilding of an exact copy of the other strand." },
    { q: "Which scientist produced Photograph 51, the X-ray diffraction image that provided key evidence for the double helix structure of DNA?", o: ["Francis Crick", "James Watson", "Rosalind Franklin", "Maurice Wilkins"], a: 2, exp: "Rosalind Franklin used X-ray crystallography to produce Photograph 51 in 1952, which showed the helical structure of DNA." },
    { q: "Who published the double helix model of DNA in Nature in 1953?", o: ["Franklin and Wilkins", "Watson and Crick", "Pauling and Bragg", "Mendel and Darwin"], a: 1, exp: "Watson and Crick published their double helix model in Nature in April 1953, building on data including Franklin's X-ray images." },
    { q: "Why was Rosalind Franklin not awarded the 1962 Nobel Prize for the discovery of DNA's structure?", o: ["She was not involved in the research", "Nobel Prizes are not awarded posthumously and she had died in 1958", "She refused the prize on ethical grounds", "Her data was shown to be incorrect"], a: 1, exp: "Franklin died from cancer in 1958 at age 37; the Nobel Prize is not awarded posthumously, so she was ineligible for the 1962 prize." },
    { q: "In asexual reproduction, offspring are:", o: ["Genetically different from the parent due to mutation", "Genetically identical to the parent (clones)", "Produced from two parents", "Always more adapted than the parent"], a: 1, exp: "In asexual reproduction, a single parent produces genetically identical offspring because no shuffling of genetic material occurs." },
    { q: "Which type of cell division produces gametes and halves the chromosome number?", o: ["Mitosis", "Meiosis", "Binary fission", "Budding"], a: 1, exp: "Meiosis is the specialised cell division that produces gametes with half the normal chromosome number." },
    { q: "What is a zygote?", o: ["A sex cell produced by meiosis", "The cell formed when an egg and sperm fuse during fertilisation", "A clone produced by asexual reproduction", "A cell that has undergone mutation"], a: 1, exp: "A zygote is the single cell formed when a sperm fertilises an egg; it contains a full set of chromosomes from both parents." },
    { q: "What does the term 'phenotype' mean?", o: ["The set of alleles an organism carries", "The observable characteristics of an organism", "The number of chromosomes in a cell", "The process by which genes are expressed"], a: 1, exp: "The phenotype is the observable physical or biochemical characteristics of an organism, resulting from its genotype and environment." },
    { q: "What does the term 'genotype' mean?", o: ["The observable traits of an organism", "The specific combination of alleles an organism carries", "The process of chromosome separation", "The complete genome of a species"], a: 1, exp: "The genotype is the specific combination of alleles an organism possesses for a given gene or genes." },
    { q: "A sample of DNA contains 30% adenine. What percentage of bases are guanine?", o: ["30%", "20%", "40%", "25%"], a: 1, exp: "Adenine pairs with thymine (so T = 30%). The remaining 40% is split equally between C and G, giving G = 20%." },
    { q: "What is a mutation?", o: ["The process of DNA replication", "Any change to the base sequence of a DNA molecule", "The expression of a recessive allele", "The fusion of two gametes"], a: 1, exp: "A mutation is any change to the base sequence of DNA; it can involve a single base or larger segments." },
    { q: "What type of mutation occurs when a single base is replaced by a different base?", o: ["Insertion mutation", "Deletion mutation", "Point substitution mutation", "Frameshift mutation"], a: 2, exp: "A point substitution mutation is when one nucleotide base is replaced by another in the DNA sequence." },
    { q: "Which of the following is an example of a mutagen?", o: ["Histone protein", "Ultraviolet radiation", "Thymine base", "Ribosome"], a: 1, exp: "UV radiation from the sun is a mutagen — an environmental agent that can damage DNA and cause mutations." },
    { q: "Sickle cell anaemia is caused by:", o: ["A deletion of an entire chromosome", "A point substitution mutation in the haemoglobin gene", "Exposure to radiation during development", "A virus attacking red blood cells"], a: 1, exp: "Sickle cell anaemia results from a single base substitution (A to T) in the haemoglobin gene, producing misshapen red blood cells." },
    { q: "Why are most mutations described as neutral rather than harmful or beneficial?", o: ["Because mutations only occur in non-coding DNA", "Because mutation occurs rarely, so most are harmless", "Because many occur in non-coding regions or produce no amino acid change, so protein function is unaffected", "Because all organisms can repair mutations perfectly"], a: 2, exp: "Many mutations occur in non-coding regions or cause a synonymous codon change that still encodes the same amino acid, leaving the protein unchanged." },
    { q: "Two parents with brown eyes can have a blue-eyed child (assuming simple Mendelian inheritance) if:", o: ["At least one parent has a dominant allele for blue eyes", "Both parents are heterozygous, carrying a recessive allele for blue eyes", "The child undergoes a mutation during development", "One parent is homozygous dominant"], a: 1, exp: "If both parents are heterozygous (Bb), there is a 25% chance their offspring will be homozygous recessive (bb) and have blue eyes." },
    { q: "What does 'homozygous dominant' mean?", o: ["The organism carries one dominant and one recessive allele", "The organism carries two copies of the dominant allele", "The organism carries two copies of the recessive allele", "The organism shows the recessive phenotype"], a: 1, exp: "Homozygous dominant means the organism carries two identical dominant alleles (e.g. TT) for a trait." },
    { q: "A dominant allele (T) controls tall height and recessive (t) controls short. A Tt x Tt cross is performed. What fraction of offspring are expected to be short?", o: ["1/4", "1/2", "3/4", "All of them"], a: 0, exp: "A Tt x Tt cross produces a 1 TT : 2 Tt : 1 tt ratio; only tt (1/4) are short because tall (T) is dominant." },
    { q: "In a Punnett square for Ff x Ff (F = normal, f = cystic fibrosis allele), what fraction of offspring are expected to have cystic fibrosis?", o: ["1/4", "1/2", "3/4", "None"], a: 0, exp: "The cross Ff x Ff gives 1 FF : 2 Ff : 1 ff; only ff (1/4) will have cystic fibrosis because it is autosomal recessive." },
    { q: "What does a shaded circle in a pedigree diagram represent?", o: ["An unaffected female", "An affected female", "An unaffected male", "An affected male"], a: 1, exp: "In standard pedigree notation, circles represent females and shading indicates the individual is affected by the condition being tracked." },
    { q: "Squares in a pedigree diagram represent:", o: ["Females", "Affected individuals", "Males", "Carriers"], a: 2, exp: "In pedigree diagrams, squares represent males and circles represent females, regardless of whether they are affected." },
    { q: "What is Mendel's Law of Segregation?", o: ["Alleles for different genes are distributed to gametes independently", "The two alleles for a trait separate during gamete formation so each gamete carries only one allele", "Dominant alleles always mask recessive alleles", "Mutations occur at a predictable rate in each generation"], a: 1, exp: "Mendel's Law of Segregation states that the pair of alleles an organism carries separates during meiosis, so each gamete receives only one allele for each gene." },
    { q: "Which genetic technology uses a molecular 'scissors' to cut DNA at a specific target sequence?", o: ["PCR (polymerase chain reaction)", "CRISPR-Cas9 gene editing", "DNA sequencing", "Gel electrophoresis"], a: 1, exp: "CRISPR-Cas9 is a gene-editing tool that uses a guide RNA to direct the Cas9 protein to cut DNA at a precise target sequence." },
    { q: "The polymerase chain reaction (PCR) is used to:", o: ["Insert a gene from one organism into another", "Amplify (make many copies of) a small DNA sample", "Sequence the bases in a DNA molecule", "Edit specific genes in a living organism"], a: 1, exp: "PCR amplifies tiny samples of DNA by repeated cycles of heating and cooling, producing millions of copies for analysis." },
    { q: "What was the first recombinant DNA pharmaceutical approved for human use (1982)?", o: ["Aspirin", "Human insulin produced by bacteria", "The polio vaccine", "The BRCA1 gene test"], a: 1, exp: "In 1982, Humulin (human insulin produced by recombinant bacteria carrying the human insulin gene) became the first approved recombinant DNA drug." },
    { q: "Genetic testing that determines whether a healthy person carries one copy of a recessive disease allele is called:", o: ["Predictive testing", "Pharmacogenomic testing", "Carrier testing", "Prenatal screening"], a: 2, exp: "Carrier testing identifies whether an individual carries one copy of a recessive disease allele that they could pass to their children, even though they are unaffected." },
    { q: "What is a major ethical concern associated with genetic testing?", o: ["That it produces incorrect results in all cases", "That genetic information could be used by employers or insurers to discriminate against individuals", "That it requires surgery to obtain DNA samples", "That it is only available in other countries"], a: 1, exp: "A key concern is genetic privacy: if employers or insurers access genetic test results, individuals with certain gene variants could face discrimination." },
    { q: "Natural selection requires which of the following conditions?", o: ["Identical individuals in a population", "Heritable variation in traits that affects survival and reproduction", "Large body size in organisms", "A stable unchanging environment"], a: 1, exp: "Natural selection requires heritable variation (genetic differences), and selection pressure so that some variants survive and reproduce better than others." },
    { q: "What is meant by 'survival of the fittest' in evolutionary terms?", o: ["The largest organisms always survive", "Individuals best adapted to their current environment are most likely to reproduce and pass on their traits", "All organisms become physically stronger over time", "Mutations always improve organism fitness"], a: 1, exp: "'Fittest' means best adapted to the current environment; those organisms are most likely to survive, reproduce, and pass on their advantageous traits." },
    { q: "Which of the following is an example of a selection pressure?", o: ["The size of an organism's genome", "Antibiotic exposure killing susceptible bacteria", "The number of genes on a chromosome", "The method of reproduction used by an organism"], a: 1, exp: "Antibiotic exposure is a selection pressure: susceptible bacteria die, while resistant variants survive and reproduce, increasing resistance in the population." },
    { q: "How does geographic isolation contribute to the formation of new species?", o: ["It increases mutation rate immediately", "It separates a population so each group evolves independently under different selection pressures until they can no longer interbreed", "It allows more offspring to be produced", "It reduces the effect of natural selection"], a: 1, exp: "When a physical barrier separates a population, the two groups evolve independently; over time they may become so different genetically that they can no longer interbreed, forming separate species." },
    { q: "Fossils are most commonly found in which type of rock?", o: ["Igneous rock", "Metamorphic rock", "Sedimentary rock", "Granite"], a: 2, exp: "Fossils form when organism remains are buried and preserved in layers of sediment that slowly harden into sedimentary rock." },
    { q: "What are homologous structures?", o: ["Structures that perform identical functions in different species", "Structures in different species that share the same underlying anatomical structure, indicating common ancestry", "Organs that have no function in modern organisms", "Structures produced by convergent evolution"], a: 1, exp: "Homologous structures (such as the forelimbs of humans, bats, and whales) share the same basic bone arrangement, indicating descent from a common ancestor." },
    { q: "What is a vestigial structure? Give the best example.", o: ["A new organ that evolved recently", "A structure that has been reduced and largely lost its original function, such as the human appendix", "A structure unique to one species", "Any structure used for reproduction"], a: 1, exp: "A vestigial structure is a remnant of an organ that had a clear function in ancestors but is reduced or functionless in modern organisms; the human appendix is a classic example." },
    { q: "How does molecular (DNA) evidence support the theory of evolution?", o: ["All species have identical DNA sequences", "Species that share a more recent common ancestor have more similar DNA sequences", "DNA changes at the same rate in all organisms", "DNA evidence shows species do not change over time"], a: 1, exp: "The more closely related two species are by evolution, the more similar their DNA sequences; comparing DNA allows evolutionary trees to be built." },
    { q: "Who independently developed the theory of evolution by natural selection alongside Charles Darwin?", o: ["Gregor Mendel", "Alfred Russel Wallace", "Jean-Baptiste Lamarck", "Louis Pasteur"], a: 1, exp: "Alfred Russel Wallace independently developed the theory of natural selection while working in the Malay Archipelago; his letter to Darwin prompted the joint presentation in 1858." },
    { q: "What was the main error in Lamarck's theory of evolution?", o: ["He claimed organisms do not change over time", "He proposed that characteristics acquired during an organism's lifetime are passed to offspring, which is incorrect", "He denied that natural selection existed", "He incorrectly described the structure of DNA"], a: 1, exp: "Lamarck correctly argued that species change over time, but wrongly proposed that traits acquired during life (like stretched necks in giraffes) are inherited by offspring." },
    { q: "In what year did Darwin publish 'On the Origin of Species'?", o: ["1831", "1858", "1859", "1865"], a: 2, exp: "Darwin published 'On the Origin of Species by Means of Natural Selection' in 1859, presenting extensive evidence for evolution by natural selection." },
    { q: "The Modern Evolutionary Synthesis united Darwin's theory of natural selection with:", o: ["Lamarck's theory of inheritance", "Mendelian genetics and the understanding of DNA", "The fossil record alone", "Plate tectonics"], a: 1, exp: "The Modern Evolutionary Synthesis (20th century) combined Darwinian natural selection with Mendelian genetics and population genetics to create a unified theory of evolution." },
    { q: "Australian megafauna, such as Diprotodon, became extinct approximately:", o: ["10,000 years ago", "46,000 to 40,000 years ago", "250,000 years ago", "2 million years ago"], a: 1, exp: "Most Australian megafauna disappeared approximately 46,000 to 40,000 years ago, coinciding with the arrival of humans and significant climate change." },
    { q: "What do Aboriginal rock art depictions of megafauna provide as scientific evidence?", o: ["Proof that megafauna are still alive today", "Cultural and historical evidence that Aboriginal peoples observed living megafauna, helping establish when extinctions occurred", "Evidence that megafauna evolved from modern animals", "Evidence that climate change alone caused the extinctions"], a: 1, exp: "Aboriginal rock art depicting megafauna suggests these animals were alive when Aboriginal peoples were present, helping constrain the timing of extinctions." },
    { q: "HeLa cells are significant in medical research because they:", o: ["Are the first animal cells ever examined under a microscope", "Are the first human cells to be successfully grown continuously in a laboratory, contributing to many medical advances", "Were used to sequence the first human genome in 1953", "Were produced by genetic engineering in the 1980s"], a: 1, exp: "HeLa cells, taken from Henrietta Lacks in 1951, were the first immortal human cell line and have been used in thousands of studies including polio vaccine development." },
    { q: "What was the key ethical issue in the original collection of Henrietta Lacks's cells?", o: ["She asked for the cells to be destroyed", "Her cells were taken without her knowledge or consent", "The cells were collected after she recovered from her illness", "Her family received excessive financial compensation"], a: 1, exp: "Henrietta Lacks's tumour cells were collected by researcher George Gey without her knowledge or consent, which is a fundamental violation of the principle of informed consent." },
    { q: "A utilitarian ethical framework evaluates the continued use of HeLa cells by asking:", o: ["Whether Henrietta Lacks personally consented to each use", "Whether the total medical benefits to humanity outweigh the harms experienced by the Lacks family", "Whether HeLa cells are owned by a government agency", "Whether the cells are still scientifically useful today"], a: 1, exp: "Utilitarianism evaluates actions by whether they produce the greatest benefit for the greatest number; it weighs the enormous medical benefits of HeLa cells against the injustice experienced by the Lacks family." },
    { q: "A cross is performed between a black guinea pig (Bb) and a white guinea pig (bb), where B = black (dominant) and b = white. What percentage of offspring are expected to be black?", o: ["25%", "75%", "50%", "100%"], a: 2, exp: "The cross Bb x bb gives offspring Bb and bb in a 1:1 ratio; 50% are Bb (black) and 50% are bb (white)." },
    { q: "Which of the following best describes polygenic inheritance?", o: ["A single gene determining one trait with two possible alleles", "Multiple genes contributing to the variation seen in one trait", "A trait caused by a chromosomal deletion", "Inheritance of a gene located on the X chromosome"], a: 1, exp: "Polygenic inheritance means that many genes, each with small effects, combine to determine the final phenotype of a trait, such as human height." },
    { q: "Identical twins have the same DNA but can develop different heights as adults. This is because:", o: ["One twin always undergoes more mutations", "Environmental factors such as nutrition interact with the shared genotype to produce different phenotypes", "Their chromosomes are actually different despite appearance", "Natural selection acts differently on each twin"], a: 1, exp: "Identical twins share genotype but environmental factors such as diet, illness, and physical activity during childhood interact with genes to produce phenotypic differences like height." },
    { q: "What is crossing over, and when does it occur?", o: ["The random alignment of chromosomes during mitosis", "The exchange of genetic material between homologous chromosomes during meiosis, increasing genetic variation", "The replication of DNA before cell division", "The separation of sister chromatids during mitosis"], a: 1, exp: "Crossing over occurs during meiosis when homologous chromosomes exchange segments, shuffling alleles and increasing the genetic variation in gametes." }
  ],

  "reactions": [
    { q: "What does the law of conservation of mass state?", o: ["Mass is created during a chemical reaction", "Mass cannot be created or destroyed in a chemical reaction", "Mass is always lost when gases are produced", "Mass increases in exothermic reactions"], a: 1, exp: "The law of conservation of mass states that the total mass of reactants equals the total mass of products in any chemical reaction." },
    { q: "Who first formulated the law of conservation of mass, and when?", o: ["John Dalton, 1808", "Antoine Lavoisier, 1789", "Robert Boyle, 1661", "Dmitri Mendeleev, 1869"], a: 1, exp: "Antoine Lavoisier, a French chemist, formulated the law of conservation of mass in 1789 based on careful quantitative experiments." },
    { q: "When magnesium burns in open air, its mass appears to increase. The correct explanation is:", o: ["New atoms are created during combustion", "Magnesium absorbs oxygen from the air, and the combined mass is greater", "The energy released adds mass to the product", "The reaction is not obeying the law of conservation of mass"], a: 1, exp: "Magnesium combines with oxygen from the air to form magnesium oxide; the mass of oxygen absorbed equals the apparent mass increase, so total mass is conserved." },
    { q: "Why is a closed system important when demonstrating the law of conservation of mass for a reaction that produces a gas?", o: ["So the reaction happens faster", "So no gas escapes, ensuring all product mass is measured", "So the temperature stays constant", "So the reaction can be reversed easily"], a: 1, exp: "In a sealed container, all gases produced stay within the system and can be measured; if gas escapes, it appears that mass has been lost." },
    { q: "What does IUPAC stand for in chemistry?", o: ["International Union of Pure and Applied Chemistry", "International University for Pure and Applied Chemistry", "International Union of Physics and Chemistry", "Institute for Universal Principles and Applied Chemistry"], a: 0, exp: "IUPAC stands for International Union of Pure and Applied Chemistry, the body that sets standardised rules for naming chemicals." },
    { q: "What is the IUPAC name for NaCl?", o: ["Sodium oxide", "Sodium chlorate", "Sodium chloride", "Disodium chloride"], a: 2, exp: "NaCl is named sodium chloride: the metal (sodium) comes first, and the non-metal (chlorine) gets the suffix '-ide'." },
    { q: "What is the chemical formula for calcium carbonate?", o: ["CaCO3", "Ca2CO3", "CaCO2", "Ca(CO3)2"], a: 0, exp: "Calcium carbonate is CaCO3: Ca2+ and CO32- combine in a 1:1 ratio because the charges balance." },
    { q: "What is the IUPAC name for CO2?", o: ["Carbon oxide", "Carbon monoxide", "Carbon dioxide", "Dicarbon oxide"], a: 2, exp: "CO2 is carbon dioxide: 'di' indicates two oxygen atoms; covalent compounds use Greek prefixes to show the number of atoms." },
    { q: "When balancing a chemical equation, you must:", o: ["Change the subscripts of the formulas", "Add coefficients in front of formulas to balance atom numbers on both sides", "Remove atoms from the equation to make it balance", "Always add water as a product"], a: 1, exp: "Equations are balanced by placing coefficients in front of formulas — you must never change subscripts, as that would change the substance." },
    { q: "Which of the following equations is correctly balanced?", o: ["H2 + O2 -> H2O", "2H2 + O2 -> 2H2O", "H2 + 2O2 -> H2O", "2H2 + 2O2 -> 2H2O"], a: 1, exp: "2H2 + O2 -> 2H2O is balanced: 4 H atoms and 2 O atoms on each side, consistent with the law of conservation of mass." },
    { q: "What does the state symbol '(aq)' mean in a chemical equation?", o: ["The substance is a gas", "The substance is dissolved in water (aqueous)", "The substance is a solid", "The substance is liquid"], a: 1, exp: "The symbol (aq) stands for 'aqueous', meaning the substance is dissolved in water." },
    { q: "In a synthesis reaction, two or more reactants combine to form:", o: ["Two new substances", "A single product", "A salt and water", "A gas and a precipitate"], a: 1, exp: "In a synthesis (combination) reaction, the general form is A + B -> AB; two or more reactants combine to form one product." },
    { q: "Which type of reaction does this equation represent: CaCO3 -> CaO + CO2?", o: ["Synthesis", "Decomposition", "Displacement", "Neutralisation"], a: 1, exp: "This is a decomposition reaction: a single compound (CaCO3) breaks down into two simpler substances (CaO and CO2) when heated." },
    { q: "In the reaction Zn + CuSO4 -> ZnSO4 + Cu, zinc displaces copper because:", o: ["Zinc is less reactive than copper", "Zinc is more reactive than copper in the reactivity series", "Copper does not react with sulfate ions", "The reaction requires a catalyst"], a: 1, exp: "In a displacement reaction, a more reactive metal displaces a less reactive metal from its compound; zinc is more reactive than copper." },
    { q: "What are the two products of every neutralisation reaction between an acid and a base?", o: ["Carbon dioxide and water", "A salt and water", "Hydrogen gas and a salt", "An oxide and water"], a: 1, exp: "Neutralisation always produces a salt and water; for example, HCl + NaOH -> NaCl + H2O." },
    { q: "The pH scale runs from 0 to 14. A substance with pH 7 is:", o: ["Strongly acidic", "Weakly acidic", "Neutral", "Strongly alkaline"], a: 2, exp: "pH 7 is neutral; at this value the concentration of H+ ions equals the concentration of OH- ions, as in pure water." },
    { q: "Which of the following has the lowest pH (most acidic)?", o: ["Blood (pH 7.4)", "Pure water (pH 7)", "Lemon juice (pH 2)", "Baking soda solution (pH 9)"], a: 2, exp: "Lemon juice has pH 2, making it the most acidic of the options; lower pH numbers indicate higher acidity." },
    { q: "The pH scale is described as logarithmic, meaning:", o: ["Each unit change represents an additive change of 1 in acidity", "Each whole unit change represents a tenfold change in the concentration of H+ ions", "pH values above 7 are impossible", "All acids have a pH below 5"], a: 1, exp: "The pH scale is logarithmic: a pH of 3 is ten times more acidic than pH 4, and 100 times more acidic than pH 5." },
    { q: "Which indicator turns green at the neutral point during a neutralisation reaction?", o: ["Phenolphthalein", "Litmus", "Universal indicator", "Bromothymol blue"], a: 2, exp: "Universal indicator shows a rainbow of colours; green indicates approximately pH 7 (neutral), making it useful for tracking neutralisation." },
    { q: "Using collision theory, why does increasing concentration speed up a reaction?", o: ["Fewer particles collide per second", "More reactant particles in a given volume means more frequent collisions per second", "Particles gain more energy at higher concentration", "Concentration reduces activation energy"], a: 1, exp: "Higher concentration means more particles are present per unit volume, so the frequency of collisions between reactant particles increases, speeding up the reaction." },
    { q: "How does increasing temperature affect the rate of a chemical reaction?", o: ["It reduces the number of collisions", "It increases the activation energy needed", "It makes particles move faster, increasing collision frequency and energy", "It has no effect on rate"], a: 2, exp: "Higher temperature gives particles more kinetic energy, so they move faster, collide more frequently, and a greater proportion of collisions have enough energy to react." },
    { q: "What is a catalyst?", o: ["A substance that is produced in a reaction", "A substance that slows down a reaction", "A substance that speeds up a reaction without being consumed", "A substance that changes the products of a reaction"], a: 2, exp: "A catalyst speeds up a reaction by lowering the activation energy required; it is not used up in the process and can be reused." },
    { q: "Why does grinding marble chips into powder speed up their reaction with hydrochloric acid?", o: ["The mass of marble is reduced by grinding", "Powdering increases the surface area, exposing more particles to collisions with acid", "The powder changes the formula of the marble", "Grinding releases heat, increasing the temperature"], a: 1, exp: "Grinding increases surface area; more particles are exposed to the acid at once, so the frequency of effective collisions per second increases." },
    { q: "Manganese dioxide greatly speeds up the decomposition of hydrogen peroxide without being used up. Manganese dioxide is acting as:", o: ["A reactant", "A product", "A catalyst", "An inhibitor"], a: 2, exp: "Manganese dioxide acts as a catalyst for hydrogen peroxide decomposition: it greatly speeds up the reaction without being consumed." },
    { q: "Which factor does NOT affect the rate of a chemical reaction?", o: ["Temperature", "Catalyst", "Surface area", "The colour of the container"], a: 3, exp: "The colour of the container has no effect on reaction rate; the factors that do affect rate are temperature, concentration, surface area, and catalysts." },
    { q: "What are alpha particles?", o: ["High-energy electrons emitted from the nucleus", "Helium nuclei containing 2 protons and 2 neutrons", "High-energy electromagnetic radiation", "Single protons emitted from the nucleus"], a: 1, exp: "An alpha particle consists of 2 protons and 2 neutrons — identical to a helium-4 nucleus — emitted during alpha decay of a heavy nucleus." },
    { q: "In alpha decay, how does the atomic number of the parent nucleus change?", o: ["Increases by 2", "Decreases by 2", "Stays the same", "Decreases by 4"], a: 1, exp: "Alpha decay emits a particle of 2 protons and 2 neutrons; the parent nucleus loses 2 protons, so its atomic number decreases by 2." },
    { q: "In beta decay, a neutron in the nucleus converts into a proton and an electron. What happens to the atomic number?", o: ["Decreases by 1", "Stays the same", "Increases by 1", "Increases by 2"], a: 2, exp: "In beta decay, a neutron becomes a proton plus an emitted electron (beta particle); the number of protons increases by 1, so the atomic number goes up by 1." },
    { q: "What is the half-life of a radioactive isotope?", o: ["The time for the isotope to lose half its mass due to evaporation", "The time for half of the radioactive atoms in a sample to undergo decay", "The time for the isotope to become completely stable", "The energy released when half the atoms decay"], a: 1, exp: "Half-life is the time taken for exactly half of the radioactive atoms in a given sample to undergo radioactive decay." },
    { q: "Carbon-14 has a half-life of 5,730 years. If you start with 800 atoms, how many remain after two half-lives?", o: ["400", "200", "100", "50"], a: 1, exp: "After one half-life (5,730 yr): 400 atoms remain. After two half-lives (11,460 yr): 200 atoms remain." },
    { q: "Why is carbon-14 useful for dating organic materials but not rocks?", o: ["Carbon-14 does not occur in rocks", "Carbon-14 has a half-life of 5,730 years — appropriate for biological materials up to ~50,000 years old but too short for rocks billions of years old", "Rocks contain too much carbon to measure accurately", "Carbon-14 only forms in biological organisms"], a: 1, exp: "Carbon-14's half-life of 5,730 years is suitable for materials up to about 50,000 years old; rocks are far older and require isotopes with billion-year half-lives (such as uranium-238)." },
    { q: "What is nuclear fission?", o: ["Two small nuclei joining to form a larger nucleus, releasing energy", "A large unstable nucleus splitting into two smaller nuclei, releasing energy", "Protons and neutrons combining in stars to form new elements", "An electron being emitted from an unstable nucleus"], a: 1, exp: "Nuclear fission is the splitting of a large, unstable nucleus (such as uranium-235) into two smaller nuclei, releasing large amounts of energy and several neutrons." },
    { q: "What is nuclear fusion?", o: ["A large nucleus splitting into two smaller ones", "Two light nuclei joining together to form a larger nucleus, releasing energy", "A neutron being absorbed by a nucleus", "The decay of a radioactive isotope"], a: 1, exp: "Nuclear fusion involves joining two light nuclei (such as hydrogen isotopes) to form a heavier nucleus, releasing very large amounts of energy — the process powering stars." },
    { q: "Which conditions are required for nuclear fusion to occur?", o: ["Room temperature and low pressure", "Extremely high temperatures (millions of degrees) and high pressure", "A neutron trigger and a catalyst", "The presence of uranium fuel"], a: 1, exp: "Fusion requires extremely high temperatures and pressures to overcome the electrostatic repulsion between positively charged nuclei and allow them to fuse." },
    { q: "Nuclear fission is currently used in commercial power stations. Nuclear fusion:", o: ["Is used in solar panels", "Is only used in research and weapons; not yet in commercial power generation", "Produces far more radioactive waste than fission", "Requires uranium as its fuel"], a: 1, exp: "Fusion occurs in the Sun and in hydrogen bombs, and is researched in projects like ITER, but no commercial fusion power station yet exists." },
    { q: "A radioisotope used in medical imaging that has a short half-life is preferred because:", o: ["It remains active in the body for years, giving long-term data", "It decays quickly so the patient is not exposed to radiation longer than necessary", "It produces alpha particles that kill cancer cells", "It cannot be detected by imaging equipment if it lasts too long"], a: 1, exp: "Short half-lives are preferred for diagnostic radioisotopes so that the radioactive material decays and becomes harmless quickly after the imaging procedure." },
    { q: "Which of the following is an environmental concern specifically associated with nuclear power stations?", o: ["Emission of large amounts of carbon dioxide during operation", "Production of high-level radioactive waste that remains hazardous for tens of thousands of years", "Use of very large volumes of coal as fuel", "Release of sulfur dioxide causing acid rain"], a: 1, exp: "Nuclear power produces very little CO2 during operation, but generates high-level radioactive waste (spent fuel rods) that requires secure storage for thousands of years." },
    { q: "In the Haber process used in industry, which catalyst is used to speed up the production of ammonia?", o: ["Platinum", "Manganese dioxide", "Iron", "Vanadium pentoxide"], a: 2, exp: "The Haber process (N2 + 3H2 -> 2NH3) uses an iron catalyst along with high temperature and pressure to produce ammonia efficiently." },
    { q: "A 200 g sample of a radioactive isotope has a half-life of 4 days. What mass remains after 12 days?", o: ["100 g", "50 g", "25 g", "12.5 g"], a: 2, exp: "12 days is 3 half-lives. 200 -> 100 (after 4 days) -> 50 (after 8 days) -> 25 g (after 12 days)." },
    { q: "A nuclear equation must be balanced so that:", o: ["Only the atomic numbers balance", "Only the mass numbers balance", "Both mass numbers and atomic numbers balance on each side", "The total charge is zero on both sides"], a: 2, exp: "In nuclear equations, both the mass numbers (top) and atomic numbers (bottom) must add up to the same total on each side of the arrow." },
    { q: "What are the two elements produced in the greatest amounts by Big Bang nucleosynthesis?", o: ["Carbon and oxygen", "Hydrogen and helium", "Iron and nickel", "Lithium and beryllium"], a: 1, exp: "Big Bang nucleosynthesis produced about 75% hydrogen and 25% helium by mass; elements heavier than lithium formed later in stars." },
    { q: "Elements heavier than iron are produced when:", o: ["Stars fuse hydrogen in their cores", "Uranium undergoes alpha decay", "Very large stars explode as supernovae", "The Big Bang created all elements simultaneously"], a: 2, exp: "Stellar nucleosynthesis in stars produces elements up to iron; heavier elements are produced in the extreme conditions of supernova explosions." },
    { q: "Which of the following conditions causes a nucleus to be unstable?", o: ["Equal numbers of protons and neutrons in small nuclei", "Too many or too few neutrons relative to protons, or having too many total nucleons", "Having exactly 6 protons and 6 neutrons", "Being a non-metal element"], a: 1, exp: "Nuclear stability depends on the ratio of protons to neutrons; too many or too few neutrons, or a very large nucleus (more than 83 protons), causes instability and radioactive decay." },
    { q: "If a word equation states 'acid + base -> salt + water', what type of reaction is this?", o: ["Synthesis", "Decomposition", "Displacement", "Neutralisation"], a: 3, exp: "Acid + base -> salt + water is the general form of a neutralisation reaction, where the acid and base neutralise each other." },
    { q: "Gamma rays are emitted alongside alpha or beta radiation. Gamma emission:", o: ["Causes the mass number to decrease by 4", "Causes the atomic number to increase by 1", "Does not change the mass number or atomic number of the nucleus", "Converts a proton into a neutron"], a: 2, exp: "Gamma rays are high-energy electromagnetic radiation; their emission releases energy but does not change the number of protons or neutrons in the nucleus." },
    { q: "In a precipitation reaction demonstration of conservation of mass, why is the flask sealed during the experiment?", o: ["To increase the reaction rate", "To prevent any substance from leaving the system, ensuring all mass is measured", "To keep the temperature constant", "To avoid contamination from outside air"], a: 1, exp: "Sealing the flask ensures it is a closed system; no matter can escape or enter, so the mass before and after the reaction can be directly compared." },
    { q: "The Haber process produces ammonia from nitrogen and hydrogen. What are the typical conditions used?", o: ["Low temperature, low pressure, no catalyst", "High temperature (~450 degrees C), high pressure (~200 atm), iron catalyst", "Room temperature, high pressure, platinum catalyst", "Very high temperature (>1000 degrees C), low pressure, no catalyst"], a: 1, exp: "The Haber process uses approximately 450 degrees C, 200 atm pressure, and an iron catalyst to produce ammonia at a commercially viable rate." },
    { q: "A rock sample contains 1/8 of its original uranium-235. How many half-lives have passed?", o: ["2", "3", "4", "8"], a: 1, exp: "After 1 half-life: 1/2 remains. After 2: 1/4. After 3: 1/8. So three half-lives have passed." },
    { q: "Which of the following best describes the pH of human blood?", o: ["About 2 (strongly acidic)", "About 7 (neutral)", "About 7.4 (slightly alkaline)", "About 10 (moderately alkaline)"], a: 2, exp: "Human blood has a pH of approximately 7.35 to 7.45 — slightly alkaline — which must be tightly regulated for normal cell function." },
    { q: "What does the reactivity series of metals allow chemists to predict?", o: ["Which metals are electrical conductors", "Which metal will displace another from a compound in a displacement reaction", "The boiling points of different metals", "The colour of metal oxides"], a: 1, exp: "The reactivity series ranks metals from most to least reactive; a more reactive metal will displace a less reactive metal from its compound in a displacement reaction." },
    { q: "During a chemical reaction, atoms are:", o: ["Created from the energy released", "Destroyed to form new substances", "Rearranged into new combinations, but not created or destroyed", "Split into subatomic particles"], a: 2, exp: "Chemical reactions rearrange existing atoms into new combinations (new substances), but no atoms are created or destroyed, which is why mass is conserved." },
    { q: "A student measures the mass of a sealed flask before and after a chemical reaction inside it. The mass should:", o: ["Decrease because products are lighter", "Increase because energy is released", "Remain the same because mass is conserved in a closed system", "Change depending on the type of reaction"], a: 2, exp: "In a closed system, no matter can enter or leave; by the law of conservation of mass, the total mass before equals the total mass after the reaction." },
    { q: "Technetium-99m is used in medical imaging. Which property makes a radioisotope with a short half-life ideal for medical diagnosis?", o: ["It stays in the body permanently for long-term monitoring", "It emits only alpha particles that are easy to detect", "The patient's radiation exposure ends quickly as the isotope decays rapidly", "Short half-life means higher energy is released per decay"], a: 2, exp: "A short half-life ensures the radioactive isotope becomes stable (harmless) shortly after the scan, minimising the patient's total radiation dose." },
    { q: "A word equation for a displacement reaction between iron and copper sulfate solution would be:", o: ["Iron + copper sulfate -> iron sulfate + copper", "Copper + iron sulfate -> copper sulfate + iron", "Iron + copper -> iron copper sulfate", "Iron sulfate -> iron + sulfate"], a: 0, exp: "Iron is more reactive than copper; it displaces copper from the compound to form iron sulfate solution and copper metal is deposited." },
    { q: "When copper(II) carbonate is heated, it decomposes. Which gas is produced that turns limewater milky?", o: ["Oxygen", "Hydrogen", "Carbon dioxide", "Sulfur dioxide"], a: 2, exp: "Thermal decomposition of copper(II) carbonate produces copper(II) oxide and carbon dioxide; CO2 turns limewater (calcium hydroxide solution) milky white." }
  ],

  "waves": [
    { q: "Which type of wave requires a physical medium to travel through?", o: ["Electromagnetic wave", "Mechanical wave", "Light wave", "Radio wave"], a: 1, exp: "Mechanical waves (such as sound and water waves) require a medium of particles to oscillate and transfer energy; electromagnetic waves do not." },
    { q: "Why can light travel through the vacuum of space but sound cannot?", o: ["Light is faster, so it can pass through vacuum", "Sound needs a medium of particles to travel through; light is an electromagnetic wave that does not", "Sound is absorbed by space dust", "Light has a longer wavelength than sound"], a: 1, exp: "Sound is a mechanical wave requiring a medium; in the near-vacuum of space, there are no particles to carry compressions and rarefactions, so sound cannot propagate." },
    { q: "In a transverse wave, particles oscillate:", o: ["Parallel to the direction of wave travel", "Perpendicular to the direction of wave travel", "In circular paths around the wave direction", "Randomly in all directions"], a: 1, exp: "In transverse waves, particles move at right angles (perpendicular) to the direction the wave travels — e.g. a rope wave moving horizontally while the rope moves up and down." },
    { q: "In a longitudinal wave, particles oscillate:", o: ["Perpendicular to the direction of wave travel", "At 45 degrees to the direction of travel", "Parallel to the direction of wave travel", "In circular paths"], a: 2, exp: "In longitudinal waves (e.g. sound), particles oscillate back and forth in the same direction as the wave travels, creating compressions and rarefactions." },
    { q: "What are compressions and rarefactions in a sound wave?", o: ["Regions of high and low temperature in the medium", "Regions where medium particles are pushed together (compression) and spread apart (rarefaction)", "The crests and troughs of a transverse wave", "Points where the wave changes direction"], a: 1, exp: "Compressions are regions of high particle density and pressure; rarefactions are regions of low density and pressure in a longitudinal sound wave." },
    { q: "What is the amplitude of a wave?", o: ["The distance between two successive crests", "The number of complete waves passing a point per second", "The maximum displacement of a particle from its equilibrium position", "The speed at which the wave travels"], a: 2, exp: "Amplitude is the maximum displacement of a particle from its rest (equilibrium) position; greater amplitude means more energy is carried by the wave." },
    { q: "What is the unit of frequency?", o: ["Metres (m)", "Metres per second (m/s)", "Hertz (Hz)", "Seconds (s)"], a: 2, exp: "Frequency is measured in hertz (Hz), where 1 Hz means one complete wave cycle passes a given point per second." },
    { q: "A wave has a frequency of 10 Hz and a wave speed of 40 m/s. Calculate the wavelength using v = f x lambda.", o: ["4 m", "400 m", "0.25 m", "10 m"], a: 0, exp: "Rearranging v = f x lambda: lambda = v/f = 40/10 = 4 m." },
    { q: "A sound wave in air has a speed of 340 m/s and a frequency of 170 Hz. What is its wavelength?", o: ["57,800 m", "2 m", "0.5 m", "510 m"], a: 1, exp: "lambda = v/f = 340/170 = 2 m." },
    { q: "The wave equation v = f x lambda tells us that if frequency doubles while speed remains constant:", o: ["Wavelength also doubles", "Wavelength is halved", "Amplitude doubles", "Wave speed doubles"], a: 1, exp: "From v = f x lambda, if v is constant and f doubles, then lambda must halve: lambda = v/f." },
    { q: "All electromagnetic waves travel at approximately what speed in a vacuum?", o: ["340 m/s", "1,500 m/s", "3 x 10^8 m/s", "3 x 10^6 m/s"], a: 2, exp: "All electromagnetic waves travel at approximately 3 x 10^8 m/s (the speed of light) in a vacuum, regardless of their frequency." },
    { q: "List the electromagnetic spectrum in order from LOWEST to HIGHEST frequency.", o: ["Gamma, X-ray, UV, visible, infrared, microwave, radio", "Radio, microwave, infrared, visible, ultraviolet, X-ray, gamma ray", "Radio, infrared, visible, ultraviolet, microwave, X-ray, gamma ray", "Visible, radio, microwave, infrared, UV, X-ray, gamma ray"], a: 1, exp: "From lowest to highest frequency: radio waves, microwaves, infrared, visible light, ultraviolet, X-rays, gamma rays." },
    { q: "Why are gamma rays more dangerous to living tissue than radio waves?", o: ["Gamma rays travel faster than radio waves", "Gamma rays have much higher frequency and energy per photon, making them ionising and able to damage DNA", "Gamma rays are mechanical waves that push through tissue", "Radio waves cannot penetrate the body at all"], a: 1, exp: "Higher frequency EM waves carry more energy per photon; gamma rays are ionising — they have enough energy to remove electrons from atoms and damage DNA." },
    { q: "Which part of the electromagnetic spectrum is used in medical imaging to view broken bones?", o: ["Radio waves", "Infrared", "Ultraviolet", "X-rays"], a: 3, exp: "X-rays penetrate soft tissue but are absorbed by denser material like bone, producing shadow images on a detector to reveal fractures." },
    { q: "Which property of sound is determined by the frequency of the sound wave?", o: ["Volume (loudness)", "Pitch", "Speed", "Direction of travel"], a: 1, exp: "The pitch of a sound — how high or low it sounds — is determined by the frequency; higher frequency = higher pitch." },
    { q: "Which property of sound is determined by the amplitude of the sound wave?", o: ["Pitch", "Speed", "Volume (loudness)", "Frequency"], a: 2, exp: "The loudness (volume) of a sound is determined by amplitude; larger amplitude means greater pressure variation and a louder sound." },
    { q: "The normal hearing range for humans is approximately:", o: ["0.02 Hz to 200 Hz", "20 Hz to 20,000 Hz", "200 Hz to 200,000 Hz", "1 Hz to 1,000 Hz"], a: 1, exp: "Humans can typically hear sounds from 20 Hz (very low bass) to 20,000 Hz (20 kHz); sounds above this are ultrasound, below are infrasound." },
    { q: "What is the Doppler effect?", o: ["The bending of sound around corners", "The change in observed frequency of a wave when the source and observer are in motion relative to each other", "The reflection of sound off hard surfaces", "The absorption of sound by soft materials"], a: 1, exp: "The Doppler effect is the change in the observed frequency (and therefore pitch) of a wave when the source or observer is moving relative to the other." },
    { q: "An ambulance approaches you at high speed while its siren is sounding. You hear the siren pitch as:", o: ["Lower than it actually is", "The same as it actually is", "Higher than it actually is", "Silent until it reaches you"], a: 2, exp: "As the ambulance approaches, the compressions arrive more frequently than they are emitted; the observed frequency is higher, so the pitch sounds higher." },
    { q: "What is redshift in astronomy, and how is it related to the Doppler effect?", o: ["Stars appearing red due to dust in space", "The shift of a star's light to longer wavelengths when the star is moving away from Earth — the light equivalent of the Doppler effect", "Stars becoming redder as they cool down", "The reflection of red light by distant planets"], a: 1, exp: "Redshift occurs when a light source moves away from an observer; the Doppler effect stretches the light waves to longer (redder) wavelengths." },
    { q: "Sound travels fastest through which medium?", o: ["Air at 0 degrees C", "Air at 20 degrees C", "Water", "Steel"], a: 3, exp: "Sound speed depends on the closeness and elasticity of particles; in dense solids like steel (~5000 m/s), particles are very close, so energy transfers much faster than in air (~340 m/s)." },
    { q: "The law of reflection states that:", o: ["The angle of incidence is always 90 degrees", "The angle of incidence equals the angle of refraction", "The angle of incidence equals the angle of reflection, both measured from the normal", "Light is always absorbed when it hits a surface"], a: 2, exp: "The law of reflection: the angle of incidence = the angle of reflection, where both angles are measured from the normal (a line perpendicular to the surface at the point of contact)." },
    { q: "A red apple appears red because:", o: ["It emits red light produced by chemical reactions", "It absorbs all wavelengths of visible light and reflects only red wavelengths back to our eyes", "It refracts red light more than other colours", "It produces red fluorescence under UV light"], a: 1, exp: "Objects appear coloured because they selectively absorb some wavelengths and reflect others; a red apple absorbs most wavelengths but reflects red wavelengths." },
    { q: "Why does a straw appear bent when viewed in a glass of water?", o: ["The straw physically bends under water pressure", "Light refracts (changes direction) as it passes from denser water into less dense air", "Total internal reflection occurs at the water surface", "The eye cannot detect light coming through water"], a: 1, exp: "Refraction: light slows down as it enters denser water, bending towards the normal; as it exits into less dense air, it bends away, shifting the apparent position of the straw." },
    { q: "Why does the sky appear blue during daytime?", o: ["The atmosphere contains blue gas molecules", "Water in the atmosphere absorbs other colours", "Rayleigh scattering causes gas molecules to scatter shorter blue wavelengths more than longer red wavelengths across the sky", "The Sun emits mostly blue light"], a: 2, exp: "Rayleigh scattering: small gas molecules in the atmosphere scatter short-wavelength blue light in all directions much more than longer-wavelength red light, so the sky looks blue." },
    { q: "Why do sunsets appear orange and red?", o: ["The Sun cools down at sunset and emits longer wavelengths", "Atmospheric pollution absorbs blue light", "At low angles, sunlight travels through more atmosphere; most blue light is scattered away, leaving the longer red and orange wavelengths", "The ozone layer reflects blue light back into space"], a: 2, exp: "At sunset, light travels through a longer path of atmosphere; most of the blue light is scattered away, so predominantly longer-wavelength red and orange light reaches the observer." },
    { q: "What is the function of the cochlea in the human ear?", o: ["It collects and funnels sound into the ear canal", "It amplifies and transmits vibrations from the eardrum to the inner ear", "It analyses sound frequencies using hair cells and converts mechanical vibrations to electrical signals", "It equalises air pressure between the outer and middle ear"], a: 2, exp: "The cochlea is a fluid-filled spiral structure in the inner ear; different hair cells along its length respond to different frequencies and generate electrical signals sent to the brain." },
    { q: "What are the three small bones (ossicles) in the middle ear?", o: ["Pinna, cochlea, and auditory nerve", "Eardrum, oval window, and cochlea", "Malleus (hammer), incus (anvil), and stapes (stirrup)", "Rod, cone, and optic nerve"], a: 2, exp: "The three ossicles — malleus, incus, and stapes — amplify vibrations from the eardrum and transmit them to the fluid-filled inner ear." },
    { q: "Ultrasound used in medical imaging operates at frequencies:", o: ["Below the threshold of human hearing (below 20 Hz)", "In the normal human hearing range (20 Hz to 20 kHz)", "Above the human hearing limit — typically 1 MHz to 20 MHz", "In the microwave range of the electromagnetic spectrum"], a: 2, exp: "Medical ultrasound uses frequencies far above human hearing — typically 1 to 20 MHz — because high frequency gives better image resolution." },
    { q: "Why is ultrasound preferred over X-rays for imaging a developing foetus?", o: ["Ultrasound produces sharper images than X-rays", "Ultrasound is non-ionising and poses no known radiation risk to the foetus or mother", "Ultrasound is cheaper than X-rays", "X-rays cannot penetrate the mother's skin"], a: 1, exp: "Ultrasound is a non-ionising mechanical wave; unlike X-rays (ionising EM radiation), it does not damage DNA, making it safe for repeated use in pregnancy monitoring." },
    { q: "What is distance in kinematics?", o: ["The straight-line change in position from start to finish", "The total length of the path an object has travelled", "The rate of change of velocity", "The force applied to an object"], a: 1, exp: "Distance is a scalar quantity — the total length of path travelled — regardless of direction; it does not account for direction and is always positive." },
    { q: "What is displacement?", o: ["The total distance travelled, regardless of direction", "The straight-line distance and direction from start to finish position", "The rate of change of speed", "The force that causes acceleration"], a: 1, exp: "Displacement is a vector quantity — the straight-line distance and direction from an object's starting point to its ending point." },
    { q: "A runner completes one full lap of a 400 m circular track. Their displacement is:", o: ["400 m", "800 m", "0 m, because they returned to the starting point", "200 m"], a: 2, exp: "Displacement is the change in position from start to finish; returning to the start means the start and end points are the same, so displacement = 0." },
    { q: "A car travels 120 km in 1.5 hours. What is its average speed?", o: ["60 km/h", "80 km/h", "90 km/h", "180 km/h"], a: 1, exp: "Average speed = distance / time = 120 / 1.5 = 80 km/h." },
    { q: "What does the gradient (slope) of a distance-time graph represent?", o: ["Acceleration", "Force", "Speed", "Displacement"], a: 2, exp: "The gradient of a distance-time graph at any point equals the speed of the object at that instant." },
    { q: "On a speed-time graph, what does the area under the line represent?", o: ["Acceleration", "Force applied", "Distance travelled", "Speed at a point in time"], a: 2, exp: "The area under a speed-time graph gives the total distance travelled during that time interval." },
    { q: "What does a horizontal (flat) line on a speed-time graph indicate?", o: ["The object is stationary", "The object is accelerating", "The object is moving at constant speed", "The object is decelerating"], a: 2, exp: "A horizontal line on a speed-time graph means speed is not changing — the object moves at constant speed (zero acceleration)." },
    { q: "What is acceleration?", o: ["The total distance divided by the total time", "The rate of change of velocity — how quickly speed or direction changes", "The force applied per unit mass", "The total displacement of an object"], a: 1, exp: "Acceleration is the rate of change of velocity (a = change in v / t); it is measured in m/s^2 and is a vector quantity." },
    { q: "State Newton's first law of motion (law of inertia).", o: ["Force equals mass times acceleration", "Every action has an equal and opposite reaction", "An object at rest stays at rest and an object in motion stays in motion at constant velocity unless acted on by a net force", "Heavier objects fall faster than lighter objects"], a: 2, exp: "Newton's first law: objects maintain their state of rest or uniform motion unless a net external force acts on them — this is the principle of inertia." },
    { q: "A 4 kg object is acted on by a net force of 20 N. What is its acceleration?", o: ["80 m/s^2", "5 m/s^2", "16 m/s^2", "0.2 m/s^2"], a: 1, exp: "Using F = ma: a = F/m = 20/4 = 5 m/s^2." },
    { q: "Newton's third law states:", o: ["Acceleration is proportional to net force", "Objects resist changes in motion", "For every action force there is an equal and opposite reaction force acting on a different object", "Heavier objects need greater force to accelerate"], a: 2, exp: "Newton's third law: when object A exerts a force on object B, object B simultaneously exerts a force of equal magnitude and opposite direction on object A." },
    { q: "A 1200 kg car accelerates from rest to 20 m/s in 8 seconds. What is the net force required?", o: ["150 N", "3000 N", "24000 N", "2400 N"], a: 1, exp: "Acceleration = (20-0)/8 = 2.5 m/s^2. F = ma = 1200 x 2.5 = 3000 N." },
    { q: "What is inertia?", o: ["The net force acting on an object", "The tendency of an object to resist changes to its state of motion", "The acceleration produced by gravity", "The energy stored in a moving object"], a: 1, exp: "Inertia is the property of matter that causes objects to resist changes in motion; the greater the mass, the greater the inertia." },
    { q: "Why must passengers wear seatbelts in cars? Which Newton's law explains this?", o: ["Newton's second law: to reduce the acceleration force", "Newton's first law: without a seatbelt, a passenger continues forward at the car's speed when the car suddenly stops", "Newton's third law: the car's braking force is matched by the passenger's force", "Seatbelts are a legal requirement but have no physics explanation"], a: 1, exp: "Newton's first law: an unrestrained passenger continues moving at the car's speed when the car brakes; the seatbelt provides the force needed to decelerate the passenger too." },
    { q: "What does it mean when the net force on an object is zero?", o: ["The object must be stationary", "The object must be accelerating", "The object is in equilibrium — either at rest or moving at constant velocity", "The object has no mass"], a: 2, exp: "Zero net force means all forces are balanced (equilibrium); by Newton's first law, the object either remains at rest or continues moving at constant velocity." },
    { q: "Three forces act on an object: 20 N right, 8 N right, and 15 N left. What is the net force?", o: ["13 N to the right", "13 N to the left", "43 N to the right", "7 N to the right"], a: 0, exp: "Net force = 20 + 8 - 15 = 13 N to the right (taking right as positive)." },
    { q: "What does a curved, increasingly steep line on a distance-time graph indicate?", o: ["Constant speed", "Deceleration", "Stationary object", "Acceleration — speed is increasing over time"], a: 3, exp: "On a distance-time graph, an increasing gradient (steepening curve) means the object is covering more distance per unit time — it is accelerating." },
    { q: "The didgeridoo produces lower-pitched notes when it is longer because:", o: ["Longer tubes absorb more sound energy", "A longer air column resonates at a lower fundamental frequency", "Eucalyptus wood vibrates more slowly than other woods", "The player breathes more slowly into longer instruments"], a: 1, exp: "A longer air column inside the didgeridoo resonates at a lower fundamental frequency, producing a deeper (lower pitch) sound." },
    { q: "How do astronomers use spectroscopy to determine the chemical composition of a star?", o: ["By measuring the brightness of the star across wavelengths", "By identifying specific absorption lines in the star's spectrum, which act as a unique fingerprint for each element", "By observing the star's colour through a telescope", "By measuring the Doppler shift of the star's radio emissions"], a: 1, exp: "When a star's light is split into a spectrum, dark absorption lines appear at wavelengths specific to each element; matching these lines identifies the elements in the star's atmosphere." },
    { q: "In the cornea of the eye, incoming light is focused primarily by the process of:", o: ["Absorption", "Reflection", "Refraction", "Scattering"], a: 2, exp: "The cornea is a transparent curved surface that performs most of the eye's refraction (bending) of incoming light to focus it on the retina." },
    { q: "What is the difference between rods and cones in the retina?", o: ["Rods detect colour, cones detect light intensity", "Cones detect colour in bright light; rods detect light intensity and movement in dim conditions", "Both rods and cones detect colour equally", "Rods are found only at the edge of the retina and detect nothing"], a: 1, exp: "Cones require bright light and enable colour vision (three types: red, green, blue); rods are more sensitive, enabling vision in low light but not colour discrimination." },
    { q: "A police speed camera uses the Doppler effect of reflected radar. If a car is approaching the camera, the reflected radar waves have:", o: ["Lower frequency than the emitted waves", "The same frequency as the emitted waves", "Higher frequency than the emitted waves", "No measurable frequency difference"], a: 2, exp: "When a car approaches, it reflects radar waves back towards the camera compressed into shorter wavelengths (higher frequency); the frequency shift is proportional to the car's speed." },
    { q: "A wave on a string has a wavelength of 0.5 m and travels at 20 m/s. What is its frequency?", o: ["10 Hz", "40 Hz", "0.025 Hz", "10,000 Hz"], a: 1, exp: "f = v / lambda = 20 / 0.5 = 40 Hz." },
    { q: "A horizontal line on a distance-time graph indicates:", o: ["The object is moving at constant speed", "The object is accelerating", "The object is stationary", "The object is decelerating"], a: 2, exp: "A horizontal line on a distance-time graph means distance is not increasing with time — the object is not moving (stationary)." },
    { q: "Microwaves are used to heat food in a microwave oven because:", o: ["They are the highest energy part of the electromagnetic spectrum", "They are absorbed by water molecules in food, transferring energy and heating the food", "They reflect off all food surfaces, generating heat", "They travel more slowly through food than other EM waves, releasing energy"], a: 1, exp: "Microwaves at 2.45 GHz are absorbed by water molecules in food, causing them to vibrate and increasing the thermal energy of the food." }
  ],

  "data2": [
    { q: "Which of the following is an investigable scientific question?", o: ["What is the meaning of life?", "Is classical music better than pop?", "Does increasing fertiliser concentration affect the height of bean plants over four weeks?", "Which political party has better policies?"], a: 2, exp: "An investigable question involves measurable variables, can be answered by collecting evidence, and is achievable with available resources." },
    { q: "A question about changes in Arctic ice coverage over 50 years might still be investigable by a student because:", o: ["The student can wait 50 years to collect the data", "Long-term datasets already exist from satellites and measurements that the student can analyse", "Arctic ice does not actually change over time", "Such questions are not investigated in science"], a: 1, exp: "Existing long-term datasets (e.g. from NASA or NSIDC) allow students to analyse decades of ice coverage data without having to collect it themselves." },
    { q: "What is the independent variable in a scientific investigation?", o: ["The variable that is measured as an outcome", "The variable that is deliberately changed by the investigator", "A variable that must be kept constant throughout", "The background conditions of the experiment"], a: 1, exp: "The independent variable is the factor the investigator deliberately changes to observe its effect on the dependent variable." },
    { q: "What is the dependent variable in a scientific investigation?", o: ["The variable deliberately changed by the investigator", "A variable that is kept constant throughout", "The variable measured to determine the effect of the independent variable", "The hypothesis statement"], a: 2, exp: "The dependent variable is what is measured; it 'depends' on any changes made to the independent variable." },
    { q: "Why must controlled variables be kept constant in an investigation?", o: ["To make the experiment run faster", "To ensure any change in the dependent variable is caused only by the independent variable, not by other factors", "To satisfy safety requirements", "To make graphs easier to draw"], a: 1, exp: "Controlling all other variables ensures a fair test: if multiple things change at once, we cannot know which caused the observed effect on the dependent variable." },
    { q: "A hypothesis must be:", o: ["Always proven correct before an investigation begins", "Vague enough to cover all possible outcomes", "A specific, testable prediction that can in principle be proven false", "Written after data is collected and analysed"], a: 2, exp: "A scientific hypothesis is a specific, testable, and falsifiable prediction; it must be written before data collection and could potentially be disproved by evidence." },
    { q: "What does 'falsifiable' mean when applied to a scientific hypothesis?", o: ["It means the hypothesis has already been shown to be wrong", "It means the hypothesis can in principle be disproven by experimental evidence", "It means the hypothesis has no practical value", "It means the hypothesis is false"], a: 1, exp: "A falsifiable hypothesis makes predictions specific enough that an experiment could potentially produce results that contradict it; Karl Popper identified this as the key criterion for science." },
    { q: "What happens during peer review of a scientific paper?", o: ["The scientist reviews their own work for errors", "The government approves the results for public release", "Independent experts in the field examine the methods, data, analysis, and conclusions before publication", "Students vote on whether the findings are correct"], a: 2, exp: "Peer review involves independent scientists in the same field critically evaluating a study's design, analysis, and conclusions before it is published in a journal." },
    { q: "Why is replication important in science?", o: ["To ensure all scientists agree before research is published", "To confirm that a finding is real and not due to chance or errors specific to one lab", "To speed up the publication process", "To produce more data than one scientist can analyse"], a: 1, exp: "Replication means independent researchers reproduce the experiment; if results cannot be replicated, the original finding is considered unreliable." },
    { q: "The discovery that stomach ulcers are caused by H. pylori (Marshall and Warren, 1980s) demonstrates which feature of science?", o: ["Science never changes its explanations", "Scientific knowledge is self-correcting: new evidence can overturn established beliefs", "All scientific discoveries come from a single experiment", "Medical discoveries require no peer review"], a: 1, exp: "H. pylori challenged the accepted view (stress causes ulcers); when antibiotic treatment cured ulcers and evidence accumulated, the scientific community updated its position — showing science is self-correcting." },
    { q: "Which of the following is a red flag indicating an online source may be unreliable?", o: ["The article was published in a peer-reviewed journal", "The author has relevant academic qualifications", "The claim appears on only one website with no citations to primary sources", "The information is corroborated by multiple independent reputable sources"], a: 2, exp: "A claim appearing on a single website with no citations is a red flag; reliable scientific information is supported by multiple independent sources and linked to primary evidence." },
    { q: "Why is an anonymous author on a website a concern when evaluating the reliability of health information?", o: ["It means the information is automatically correct", "Without knowing the author's qualifications or affiliations, it is impossible to assess their expertise or potential bias", "Anonymous articles are always from government sources", "Anonymity means the author has no commercial interest"], a: 1, exp: "If the author is not identified, there is no way to verify their qualifications, institutional affiliation, or potential conflicts of interest that could bias the information." },
    { q: "According to the SIFT method for evaluating online sources, what does the 'I' stand for?", o: ["Ignore anything that seems wrong", "Investigate the source of the information", "Include multiple viewpoints", "Identify the author's nationality"], a: 1, exp: "In the SIFT method, 'I' stands for Investigate the Source — check who published the content, their credentials, and potential biases before using the information." },
    { q: "What is pseudoscience?", o: ["Any scientific claim that has not yet been tested", "Practices or claims that appear scientific but lack features that make science reliable, such as falsifiability and peer review", "A branch of science dealing with mental phenomena", "A scientific theory that has been recently updated"], a: 1, exp: "Pseudoscience uses the surface features of science (technical language, graphs) but does not follow scientific methods; claims are typically unfalsifiable and cannot be replicated." },
    { q: "Which feature best distinguishes a scientific claim from a pseudoscientific one?", o: ["A scientific claim uses complicated language", "A scientific claim has been verified by celebrities", "A scientific claim makes falsifiable predictions that have been tested and independently replicated", "A scientific claim has been around for a longer time"], a: 2, exp: "Science makes specific predictions that could be disproved, tests them in controlled conditions, and requires independent replication; pseudoscience typically lacks these features." },
    { q: "The original 1998 study claiming a link between the MMR vaccine and autism was later found to be:", o: ["A landmark study still cited by researchers today", "A fraudulent, fabricated study that was retracted; the author lost his medical licence", "A study with minor methodological flaws that was partially replicated", "An early study later confirmed by large-scale research"], a: 1, exp: "The Wakefield 1998 study was exposed as fraudulent; it was retracted and Wakefield lost his medical licence. Over 1.2 million children in subsequent studies confirmed no link between vaccines and autism." },
    { q: "Why are anecdotal testimonials ('it worked for me') not considered scientific evidence?", o: ["Because only doctors can provide reliable testimonials", "Because a single personal experience cannot rule out placebo effect, natural recovery, or coincidence; it lacks controlled conditions", "Because testimonials are always paid for by companies", "Because anecdotes are not published in journals"], a: 1, exp: "Without a control group, it is impossible to determine whether improvement was due to the treatment, placebo effect, or natural recovery; science requires controlled comparisons." },
    { q: "What is cherry-picking of data?", o: ["Selecting only the best fresh data for analysis", "Selecting only the subset of data that supports a desired conclusion while ignoring contradictory data", "A method for cleaning large datasets", "A standard statistical technique for identifying outliers"], a: 1, exp: "Cherry-picking means reporting only the data points that support your conclusion and ignoring those that contradict it, creating a misleading impression of the evidence." },
    { q: "A graph has its y-axis starting at 95 instead of 0, making a small difference between two bars look dramatic. This is an example of:", o: ["Cherry-picking", "P-hacking", "Truncated y-axis distortion", "Spurious correlation"], a: 2, exp: "A truncated (non-zero) y-axis compresses the scale so that small absolute differences appear visually large, misleading the reader about the magnitude of the difference." },
    { q: "A drug reduces the risk of a disease from 4% to 2%. The relative risk reduction is 50%. The absolute risk reduction is:", o: ["50%", "25%", "2 percentage points", "4 percentage points"], a: 2, exp: "Absolute risk reduction = 4% - 2% = 2 percentage points. The relative figure (50%) sounds impressive but represents only a 2% absolute change, which gives very different context." },
    { q: "What is p-hacking?", o: ["Running many statistical tests until one gives a significant result by chance, then reporting only that test", "Using a large sample to guarantee a low p-value", "Adjusting the p-value threshold to make results look better", "Plotting data points on a graph multiple times"], a: 0, exp: "P-hacking (also called data dredging) involves running many tests on the same data until one happens to give p < 0.05 by chance, then reporting only that test as if it were planned." },
    { q: "What is a large dataset?", o: ["Any dataset with more than 10 rows", "A dataset collected in a laboratory over one year", "A collection of many records and variables, often from systematic measurement or observation across a population or over time", "A dataset stored on a computer rather than paper"], a: 2, exp: "Large datasets contain many records (often thousands to millions) and multiple variables, generated through systematic observation, sensors, surveys, or digital records at population scale." },
    { q: "Which Australian organisation collects and publishes Australia's national census data?", o: ["Bureau of Meteorology (BOM)", "Australian Institute of Health and Welfare (AIHW)", "Australian Bureau of Statistics (ABS)", "NSW Environment Protection Authority (EPA)"], a: 2, exp: "The Australian Bureau of Statistics (ABS) conducts the national census and publishes population, social, economic, and housing data for Australia." },
    { q: "What is the mean of the dataset: 10, 20, 30, 40, 50?", o: ["20", "25", "30", "35"], a: 2, exp: "Mean = (10+20+30+40+50)/5 = 150/5 = 30." },
    { q: "Which measure of central tendency is most resistant to the effect of extreme outliers?", o: ["Mean", "Median", "Mode", "Range"], a: 1, exp: "The median (middle value when data are ordered) is not affected by extreme outliers, whereas the mean can be pulled significantly by a single very high or very low value." },
    { q: "A dataset of 10 test scores includes one score of 98 while the rest are between 55 and 76. Why might the median be a better measure than the mean for this dataset?", o: ["The mean is always wrong for test data", "The outlier score of 98 pulls the mean upward, so the median better represents the typical student", "The median is always larger than the mean", "The median ignores the highest and lowest scores completely"], a: 1, exp: "The outlier score (98) inflates the mean above most students' scores; the median, which is unaffected by the outlier, better represents the central tendency of this dataset." },
    { q: "What does standard deviation measure in a dataset?", o: ["The difference between the maximum and minimum values", "The average distance of data values from the mean", "The most common value in the dataset", "The total sum of all values"], a: 1, exp: "Standard deviation measures the average spread of data values around the mean; a small SD means values cluster tightly around the mean, a large SD means they are spread widely." },
    { q: "In a bivariate analysis, a scatter plot with all points closely following a straight line from bottom-left to top-right indicates:", o: ["No relationship between the two variables", "A strong negative correlation", "A strong positive correlation", "A causal relationship between the variables"], a: 2, exp: "A tight cluster of points rising from left to right indicates a strong positive correlation (r close to +1): as one variable increases, the other reliably increases." },
    { q: "A correlation coefficient of r = -0.88 means:", o: ["A weak positive relationship", "A strong positive relationship", "A strong negative relationship", "No relationship between the variables"], a: 2, exp: "r = -0.88 is close to -1, indicating a strong negative correlation: as one variable increases, the other tends to decrease substantially." },
    { q: "What is a confounding variable?", o: ["The variable the investigator deliberately changes", "A third variable that influences both of the variables being studied, creating a false apparent correlation between them", "A variable that is measured but not reported", "The variable most strongly correlated with the dependent variable"], a: 1, exp: "A confounding variable (lurking variable) influences both variables under study; for example, hot weather causes both higher ice cream sales and more drowning deaths — neither causes the other." },
    { q: "Which of the following is the best example of correlation being mistaken for causation?", o: ["Taller buildings have more floors — height causes the extra floors", "Ice cream sales increase in summer and so do drowning rates — but hot weather causes both; ice cream does not cause drowning", "More exercise leads to lower resting heart rate — exercise causes the lower heart rate", "More sunlight causes plants to grow faster — sunlight causes the growth"], a: 1, exp: "Ice cream sales and drowning deaths are correlated because both are caused by a third variable (hot weather); this is a classic example of confounding." },
    { q: "What is a spurious correlation?", o: ["A correlation caused by a confounding variable", "A coincidental correlation between two variables that have no causal connection whatsoever", "A correlation that has been disproven by peer review", "A correlation that reverses depending on the season"], a: 1, exp: "A spurious correlation is a purely coincidental statistical relationship between two variables with no causal mechanism; for example, Nicolas Cage film appearances correlating with pool drownings." },
    { q: "What does 'reverse causation' mean?", o: ["A correlation where neither variable causes the other", "A situation where the assumed cause is actually the effect, and the assumed effect is actually the cause", "A negative correlation", "Repeating an experiment to reverse an unexpected finding"], a: 1, exp: "Reverse causation means the causal direction is opposite to what was assumed; for example, poor health causes hospitalisation, not the other way around." },
    { q: "Which of the following provides the strongest evidence for a causal relationship?", o: ["A large observational study showing a strong correlation", "A single case study", "A randomised controlled experiment with a comparison group", "A meta-analysis of observational studies"], a: 2, exp: "A controlled experiment in which participants are randomly assigned to treatment and control groups, with all other variables held constant, provides the strongest evidence for causation." },
    { q: "What does CER stand for in the context of scientific argumentation?", o: ["Correlation, Evidence, Replication", "Claim, Evidence, Reasoning", "Claim, Experiment, Result", "Conclusion, Evidence, Research"], a: 1, exp: "CER stands for Claim, Evidence, Reasoning — a framework for constructing a scientific argument that links a specific claim to supporting data through explicit scientific reasoning." },
    { q: "In the CER framework, 'evidence' refers to:", o: ["The researcher's personal opinion", "Specific data — numbers, measurements, trends, or published research findings", "The hypothesis being tested", "The limitation of the investigation"], a: 1, exp: "Evidence in a CER argument must be specific and factual: actual numbers, measurements, trends from graphs, or verified research findings — not opinions or assertions." },
    { q: "Why is it important to acknowledge limitations when writing a scientific conclusion?", o: ["It makes the conclusion longer and more impressive", "It protects the researcher from being sued", "It shows scientific honesty and allows readers to judge the appropriate confidence in the result", "It is only required for published papers, not school science"], a: 2, exp: "Acknowledging limitations (small sample size, measurement error, uncontrolled variables) shows scientific integrity and helps readers assess how much confidence to place in the findings." },
    { q: "What is a univariate analysis?", o: ["Analysing the relationship between two variables", "Examining the distribution, central tendency, and spread of a single variable", "Comparing data from two separate populations", "Performing multiple regression on all variables"], a: 1, exp: "Univariate analysis examines one variable at a time, describing its distribution using measures like mean, median, standard deviation, and graphs like histograms." },
    { q: "What is a bivariate analysis?", o: ["Analysing one variable to describe its distribution", "Analysing two variables simultaneously to investigate whether a relationship exists between them", "Using only data from two countries", "Calculating the mean and median of a dataset"], a: 1, exp: "Bivariate analysis examines the relationship between two variables using tools like scatter plots and correlation coefficients to determine if and how the variables are related." },
    { q: "A correlation coefficient of r = 0 indicates:", o: ["A perfect positive relationship", "A strong negative relationship", "No linear relationship between the variables", "An error in the calculation"], a: 2, exp: "r = 0 means there is no linear relationship between the two variables; knowing the value of one gives no predictive information about the other." },
    { q: "A student finds r = +0.85 between hours studying and test scores. Can they conclude that studying more causes higher scores?", o: ["Yes, a correlation of 0.85 proves causation", "No — correlation does not imply causation; other factors such as motivation could explain both", "Only if the sample size is over 1000", "Yes, if the finding was peer-reviewed"], a: 1, exp: "Correlation does not establish causation; a confounding variable (e.g. student motivation) might independently cause both more study time and better scores without studying being the direct cause." },
    { q: "What is 'false balance' in science journalism?", o: ["Reporting only one side of a scientific debate", "Presenting fringe or pseudoscientific views as equally credible as the scientific consensus, falsely implying equal weight of evidence", "Publishing studies without peer review", "Using truncated axes in graphs"], a: 1, exp: "False balance occurs when journalists give equal airtime to a minority pseudoscientific view alongside the scientific consensus, implying both have equal evidential support — which is misleading." },
    { q: "What is the range of possible values for the correlation coefficient r?", o: ["0 to 1", "-1 to 0", "-1 to +1", "0 to 100"], a: 2, exp: "The correlation coefficient r ranges from -1 (perfect negative linear relationship) to +1 (perfect positive linear relationship), with 0 indicating no linear relationship." },
    { q: "Which of the following describes evidence-based decision making?", o: ["Making decisions based on personal experience and tradition", "Using the best available data and scientific knowledge, combined with statistical analysis, to guide decisions", "Asking an expert what they personally think", "Using only information from a single highly reliable source"], a: 1, exp: "Evidence-based decision making involves gathering reliable data, analysing it using appropriate statistical tools, evaluating source quality, and reasoning carefully from evidence to justified decisions." },
    { q: "A study finds that cities with more libraries have lower crime rates. The most appropriate conclusion is:", o: ["Libraries cause reduced crime and councils should build more libraries immediately", "There is a correlation between library numbers and lower crime, but further investigation is needed to determine whether causation exists and to control for confounders", "The correlation proves that reading reduces criminal behaviour", "The result is spurious and can be ignored"], a: 1, exp: "Observational data showing a correlation between libraries and lower crime cannot establish causation; confounding variables (e.g. wealth, education) could explain both, and a controlled study would be needed." },
    { q: "A p-value of 0.03 in a study means:", o: ["There is a 3% probability the hypothesis is true", "There is a 97% probability the result is real", "There is a 3% probability of obtaining results as extreme as these if the null hypothesis were true", "The study should be repeated 3 times"], a: 2, exp: "A p-value tells you the probability of getting the observed result (or more extreme) if there were no real effect; it does not directly tell you the probability that the hypothesis is true." },
    { q: "Why can a result be statistically significant (p < 0.05) but not practically meaningful?", o: ["Statistical significance always means the result is important", "With a very large sample size, even tiny and unimportant differences can be statistically significant", "A low p-value means the effect size must also be large", "Practical meaning and statistical significance are the same concept"], a: 1, exp: "With a very large dataset, even a tiny difference (e.g. 0.08%) can produce p < 0.001; statistical significance tells us the effect is real, but effect size tells us whether it matters in practice." },
    { q: "What is a meta-analysis?", o: ["A single very large study", "A study that contradicts all previous studies", "A statistical technique that combines the results of many independent studies to estimate the overall effect more reliably", "A government review of science policy"], a: 2, exp: "A meta-analysis pools data or results from many independent studies using statistical methods, producing a more reliable estimate of an effect than any single study can provide." },
    { q: "What is the purpose of a confidence interval in statistics?", o: ["To state that the result was found by chance", "To express the range of values within which the true population value is likely to fall, given the sample data", "To prove causation between two variables", "To compare the mean and median of a dataset"], a: 1, exp: "A confidence interval provides a range (e.g. 95% CI: 12 to 18) within which the true population parameter is likely to lie; a wider interval reflects more uncertainty, usually from a smaller sample." },
    { q: "Which of the following would be the most investigable version of the question 'Does exercise affect health?'", o: ["Does exercise affect health?", "Is exercise good?", "Does performing 30 minutes of aerobic exercise three times per week for 8 weeks reduce resting heart rate in Year 10 students?", "How healthy are people who exercise?"], a: 2, exp: "The refined question specifies measurable variables (exercise duration/frequency and resting heart rate), a defined population, and a timeframe — making it investigable with real data." },
    { q: "A student analyses weather data from the Bureau of Meteorology and finds Sydney's mean annual temperature increased from 1910 to 2020. This is an example of:", o: ["A controlled experiment", "A case study", "A univariate analysis of a large secondary dataset", "A qualitative study"], a: 2, exp: "Examining one variable (mean annual temperature) over time using an existing large dataset is a univariate analysis; the BOM dataset is a large secondary dataset not created by the student." },
    { q: "Which of the following best describes a strong scientific argument about a claim?", o: ["The author simply states the claim confidently", "The argument connects specific evidence to the claim through explicit scientific reasoning, acknowledges counterarguments, and qualifies confidence appropriately", "The argument uses many technical words to impress the reader", "The argument is supported by a celebrity endorsement"], a: 1, exp: "A strong scientific argument uses the CER framework: specific evidence is linked to the claim through clear reasoning, counterarguments are addressed, and confidence reflects the strength of the evidence." },
    { q: "A website claims a herbal supplement 'cures cancer' and cites 'numerous studies' without links. Which evaluation criterion most clearly marks this as unreliable?", o: ["Authority — the author's credentials are not stated", "Currency — the website may be outdated", "Accuracy — claims are not linked to verifiable primary sources", "Purpose — the site appears educational"], a: 2, exp: "Accuracy is the key concern: scientific claims must be traceable to primary evidence; vague citations ('numerous studies') that cannot be verified are a major red flag for unreliability." },
    { q: "What is the difference between a question being non-investigable and being pseudoscientific?", o: ["They are exactly the same thing", "A non-investigable question cannot be answered by data collection due to resource or measurement constraints; a pseudoscientific claim is structured to resist falsification regardless of resources", "Pseudoscientific claims are always religious in nature", "Non-investigable questions are always philosophical"], a: 1, exp: "A non-investigable question may be meaningful but difficult to test given available resources (e.g. measuring all stars); a pseudoscientific claim deliberately avoids falsification by explaining away any contradictory evidence." },
    { q: "Two datasets each have a mean of 50. Dataset A has a standard deviation of 2; Dataset B has a standard deviation of 20. What does this tell you?", o: ["Both datasets are identical", "Dataset A values are much more spread out than Dataset B values", "Dataset B values cluster tightly around the mean; Dataset A is highly variable", "Dataset A has values clustered tightly around the mean; Dataset B is much more spread out"], a: 3, exp: "Standard deviation measures spread; SD = 2 means values in Dataset A cluster tightly near 50, while SD = 20 means Dataset B values are spread widely around 50." },
    { q: "Which Australian agency provides publicly available large-scale weather and climate data used in scientific research?", o: ["Australian Bureau of Statistics (ABS)", "Bureau of Meteorology (BOM)", "Australian Competition and Consumer Commission (ACCC)", "Therapeutic Goods Administration (TGA)"], a: 1, exp: "The Bureau of Meteorology (BOM) maintains long-term climate and weather records across Australia, which scientists use to study rainfall trends, temperature changes, and extreme weather events." }
  ]
};
